const body = $input.first().json.body || $input.first().json;
const data = body.data || {};
const key = data.key || {};
const msgObj = data.message || {};
const phone = (key.remoteJid || '').replace('@s.whatsapp.net', '').replace('@g.us', '');
// Prefer pre-extracted text from the backend (avoids Serveo encoding corruption)
const rawMsg = body.resolved_text
  || msgObj.conversation
  || (msgObj.extendedTextMessage && msgObj.extendedTextMessage.text)
  || (msgObj.imageMessage && msgObj.imageMessage.caption)
  || '';
const messageId = key.id || '';
const fromMe = key.fromMe === true;
const pushName = body.pushName || data.pushName || '';
const instanceName = body.instance || body.instanceName || '';
let norm = phone.replace(/\D/g, '');
if (norm.length === 10 && !norm.startsWith('20')) norm = '20' + norm;
if (norm.length > 0 && !norm.startsWith('+')) norm = '+' + norm;
return [{ json: { phone: norm, message: rawMsg, messageId, fromMe, pushName, instanceName } }];

const ext = $('Extract & Normalize').first().json;
const db = $input.first().json;
const phone = ext.phone;
const message = ext.message;
const pushName = ext.pushName;
let profile = {};
try { profile = typeof db.profile === 'string' ? JSON.parse(db.profile) : (db.profile || {}); } catch(e) {}
let mem = [];
try { mem = typeof db.memory_rows === 'string' ? JSON.parse(db.memory_rows) : (db.memory_rows || []); } catch(e) {}
if (profile.opted_out === true) return [];
const pName = profile.patient_name || pushName || '';
const cName = profile.clinic_name || 'عيادة دكتور سمايل للأسنان';
const mPhone = profile.manager_phone || '201099937072';
const today = new Date();
const todayStr = today.toISOString().split('T')[0];
const days = ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'];
const todayDay = days[today.getDay()];
const dateMap = {};
for (let i = 1; i <= 14; i++) {
  const d = new Date(today); d.setDate(today.getDate() + i);
  const dStr = d.toISOString().split('T')[0];
  dateMap[days[d.getDay()].toLowerCase()] = dStr;
}
const alreadyBooked = (Array.isArray(mem) ? mem : []).some(r => String(r.content || '').includes('<<BOOKED>>'));
const sys = `You are the WhatsApp booking assistant for ${cName}.
Today: ${todayStr} (${todayDay}).
${alreadyBooked ? '\nSTATUS: BOOKING ALREADY COMPLETED THIS SESSION.\n' : ''}
DATE REFERENCE (use EXACTLY these for day names):
- Saturday: ${dateMap['saturday']}
- Sunday: ${dateMap['sunday']}
- Monday: ${dateMap['monday']}
- Tuesday: ${dateMap['tuesday']}
- Wednesday: ${dateMap['wednesday']}
- Thursday: ${dateMap['thursday']}

AVAILABLE DOCTORS:
- Dr. Ahmed Hassan — General Dentistry
- Dr. Mona Fathy — Orthodontics

RULES:
1. NEVER redirect to phone or website. Book 100% here on WhatsApp.
2. Match patient language. Keep replies short (2-3 lines).
3. Clinic open Sat-Thu 9AM-8PM. Closed Friday.
4. BOOKING FLOW — one question per turn: Name → Date → Time → Doctor → Show summary once → Confirm.
5. CONFIRMATION DETECTION — after showing the summary, ANY of these = YES, set booking_ready=true:
   ماشي / تمام / مؤكد / نعم / اه / اهه / اوكيه / اوكي / ايوه / يلا / صح / طيب / كويس / حسنا / مظبوط / موافق / عمل / yes / ok / okay / sure / confirm / good / fine / go ahead / do it
   CRITICAL: if you already showed the booking summary ONCE and patient sends any positive word → booking_ready=true. NEVER ask to confirm twice.
6. If BOOKING ALREADY COMPLETED: reply "موعدك محجوز بالفعل ✅ هل تحتاج مساعدة أخرى؟" and booking_ready=false.
7. booking_details.doctor_name MUST be exactly "Dr. Ahmed Hassan" or "Dr. Mona Fathy".
8. Do NOT say clinic is closed once patient agreed to an alternative day.
9. Patient phone: ${phone}  Known name: ${pName || 'not provided'}

Return ONLY this JSON:
{
  "reply_message": "",
  "sentiment": "positive|negative|neutral",
  "sentiment_score": 0.0,
  "intent": "booking|complaint|inquiry|compliment|other",
  "escalate": false,
  "escalate_reason": "",
  "send_review_link": false,
  "detected_language": "arabic|english|arabizi",
  "booking_ready": false,
  "booking_details": {
    "patient_name": "",
    "appointment_date": "",
    "appointment_time": "",
    "doctor_name": "",
    "notes": ""
  }
}`;
const msgs = [{ role: 'system', content: sys }];
for (const r of (Array.isArray(mem) ? mem : [])) {
  msgs.push({ role: r.role === 'assistant' ? 'assistant' : 'user', content: String(r.content || '') });
}
msgs.push({ role: 'user', content: message });
const sid = phone + '_' + todayStr;
return [{ json: { phone, message, pushName, patientName: pName, clinicName: cName, managerPhone: mPhone, sessionId: sid, groqPayload: { model: 'llama-3.3-70b-versatile', messages: msgs, temperature: 0.1, max_tokens: 600, response_format: { type: 'json_object' } } } }];

const prev = $('Build Groq Payload').first().json;
const gr = $input.first().json;
let ai = {};
try {
  const c = gr.choices[0].message.content;
  ai = typeof c === 'string' ? JSON.parse(c) : c;
} catch(e) {
  ai = { reply_message: 'نرد عليك خلال دقايق، شكراً لصبرك 🙏', sentiment: 'neutral', sentiment_score: 0.5, intent: 'other', escalate: false, send_review_link: false, booking_ready: false, booking_details: {} };
}
const esc = v => String(v || '').replace(/'/g, "''");
const bd = ai.booking_details || {};
return [{ json: {
  ...prev, ...ai,
  phone: prev.phone, message: prev.message, pushName: prev.pushName,
  patientName: prev.patientName, clinicName: prev.clinicName,
  managerPhone: prev.managerPhone, sessionId: prev.sessionId,
  safeMsg: esc(prev.message),
  safeReply: esc(ai.reply_message || ''),
  safeName: esc(bd.patient_name || prev.patientName || ''),
  safeEscReason: esc(ai.escalate_reason || ''),
  safeNote: esc(bd.notes || ''),
  confidence: ai.confidence || 0.8,
  sentiment_score: ai.sentiment_score || 0.5,
  booking_ready: ai.booking_ready === true,
  booking_name: bd.patient_name || prev.patientName || prev.pushName || '',
  booking_date: bd.appointment_date || '',
  booking_time: bd.appointment_time || '09:00',
  booking_doctor: bd.doctor_name || '',
  booking_notes: bd.notes || ''
} }];
